params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"放射線科": "1", "検査科": "1", "リハビリテーション科": "1", "栄養科": "1", "内視鏡室": "1", "発熱外来": "1", "腫瘍内科": "1", "健康診断": "1", "予防接種": "1", "検査": "1", "栄養指導": "2", "アートメイク": "2", "アロママッサージ": "2", "乳腺外科": "2", "形成外科": "2", "婦人科": "2", "脳神経外科": "2", "皮膚科": "2", "産婦人科": "2", "other": "2"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科");
var mapping = {"放射線科": "1", "検査科": "1", "リハビリテーション科": "1", "栄養科": "1", "内視鏡室": "1", "発熱外来": "1", "腫瘍内科": "1", "健康診断": "1", "予防接種": "1", "検査": "1", "栄養指導": "2", "アートメイク": "2", "アロママッサージ": "2", "乳腺外科": "2", "形成外科": "2", "婦人科": "2", "脳神経外科": "2", "皮膚科": "2", "産婦人科": "2", "other": "2"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);
